import{_ as e,a,b as o}from"./chunks/支持留言.NiGCLVdp.js";import{_ as t,o as l,c as s,a2 as n}from"./chunks/framework.DnrXFDHb.js";const v=JSON.parse('{"title":"Blog","description":"","frontmatter":{},"headers":[],"relativePath":"it-IT/Other/blog.md","filePath":"it-IT/Other/blog.md","lastUpdated":1781962217000}'),r={name:"it-IT/Other/blog.md"};function p(c,i,d,g,u,h){return l(),s("div",null,[...i[0]||(i[0]=[n('<h1 id="blog" tabindex="-1">Blog <a class="header-anchor" href="#blog" aria-label="Permalink to &quot;Blog&quot;">​</a></h1><p>La funzione Blog aggiunge al tuo sito ImgBed una pagina blog indipendente.</p><p>Dopo l&#39;abilitazione, i visitatori possono aprire:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/blog/</span></span></code></pre></div><p><img src="'+e+'" alt="Homepage blog" loading="lazy"></p><p>Il blog deriva dal progetto open source <a href="https://github.com/LyraVoid/Mizuki" target="_blank" rel="noreferrer">LyraVoid/Mizuki</a>. ImgBed lo ha riscritto e integrato con Vue, così può funzionare come parte del sito di hosting immagini.</p><h2 id="dove-configurare" tabindex="-1">Dove configurare <a class="header-anchor" href="#dove-configurare" aria-label="Permalink to &quot;Dove configurare&quot;">​</a></h2><p>Le impostazioni blog si trovano in:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; Blog</span></span></code></pre></div><p><img src="'+a+'" alt="Impostazioni blog" loading="lazy"></p><h2 id="prima-configurazione" tabindex="-1">Prima configurazione <a class="header-anchor" href="#prima-configurazione" aria-label="Permalink to &quot;Prima configurazione&quot;">​</a></h2><ol><li>Attiva <code>Enable</code>.</li><li>Seleziona l&#39;account GitHub in cui salvare la configurazione del blog.</li><li>Clicca su <code>Update Blog</code>.</li><li>Attendi il messaggio di successo.</li><li>Apri <code>https://your-domain.com/blog/</code> per controllare il risultato.</li></ol><p>Al primo utilizzo, ImgBed prepara un repository GitHub privato nell&#39;account selezionato:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>imgbed-blog-config</span></span></code></pre></div><p>Il repository contiene impostazioni del blog e contenuti degli articoli.</p><h2 id="scrivere-articoli" tabindex="-1">Scrivere articoli <a class="header-anchor" href="#scrivere-articoli" aria-label="Permalink to &quot;Scrivere articoli&quot;">​</a></h2><p>Gli articoli si modificano nel repository GitHub privato:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>imgbed-blog-config</span></span></code></pre></div><p>Flusso tipico:</p><ol><li>Apri GitHub.</li><li>Entra nel repository privato <code>imgbed-blog-config</code>.</li><li>Modifica o aggiungi file degli articoli.</li><li>Fai commit delle modifiche.</li><li>Torna nel pannello admin di ImgBed e clicca <code>Update Blog</code>, oppure clicca tre volte il logo in alto a sinistra nella homepage del blog per avviare un aggiornamento.</li></ol><p><code>Update Blog</code> non sovrascrive gli articoli che hai scritto. Serve soprattutto a inizializzare il repository quando necessario e ad aggiornare la cache del blog.</p><h2 id="funzioni-supportate" tabindex="-1">Funzioni supportate <a class="header-anchor" href="#funzioni-supportate" aria-label="Permalink to &quot;Funzioni supportate&quot;">​</a></h2><p>Il blog supporta le funzioni comuni: lista articoli, categorie, tag, archivio, ricerca, dark mode e cambio lingua.</p><p>Supporta anche commenti e statistiche visite.</p><p><img src="'+o+'" alt="Commenti blog" loading="lazy"></p><p>I commenti compaiono sotto gli articoli. I visitatori possono inserire avatar, nickname, email e testo del commento.</p><p>Le statistiche mostrano visualizzazioni degli articoli e visite del sito, utili per capire il traffico del blog.</p><h2 id="url" tabindex="-1">URL <a class="header-anchor" href="#url" aria-label="Permalink to &quot;URL&quot;">​</a></h2><p>Il blog è sempre servito sotto <code>/blog/</code>.</p><p>Per esempio, se il dominio ImgBed è:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://image.example.com</span></span></code></pre></div><p>l&#39;URL del blog è:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://image.example.com/blog/</span></span></code></pre></div><p>Quando il blog viene disattivato, i visitatori non possono più accedere alla pagina blog.</p>',34)])])}const f=t(r,[["render",p]]);export{v as __pageData,f as default};
